terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  backend "s3" {
    bucket         = "my-tf-state"
    key            = "prod/terraform.tfstate"
    region         = "us-east-1"
    dynamodb_table = "tf-state-lock"
  }
}

provider "aws" { region = "us-east-1" }

resource "aws_s3_bucket" "logs" {
  bucket = "my-app-logs-2024"
}

output "bucket_arn" {
  value = aws_s3_bucket.logs.arn
}

terraform {
  backend "s3" {
    bucket         = "my-tf-state-prod"
    key            = "services/api/terraform.tfstate"
    region         = "us-east-1"
    encrypt        = true
    dynamodb_table = "terraform-state-lock"
  }
}

# Initialize with environment-specific overrides
# terraform init -backend-config=envs/prod/backend.hcl

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.1"

  name            = "prod-vpc"
  cidr            = "10.0.0.0/16"
  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
}

output "vpc_id" {
  value = module.vpc.vpc_id
}

locals {
  env_config = {
    dev     = { instance_type = "t3.micro", min_size = 1 }
    staging = { instance_type = "t3.small", min_size = 2 }
    prod    = { instance_type = "t3.large", min_size = 4 }
  }
  cfg = local.env_config[terraform.workspace]
}

resource "aws_autoscaling_group" "app" {
  min_size          = local.cfg.min_size
  launch_template {
    id = aws_launch_template.app.id
  }
}

import * as aws from "@pulumi/aws";
import { interpolate } from "@pulumi/pulumi";

// Type-safe: wrong arg here = compile error, not failed apply
const bucket = new aws.s3.BucketV2("assets", {
  tags: { Environment: "prod" },
});

// Native language logic — no count/for_each workaround
const envs = ["prod", "staging"];
const queues = envs.map(env =>
  new aws.sqs.Queue(`queue-${env}`, { visibilityTimeoutSeconds: 30 })
);

export const bucketArn = bucket.arn;

resource "aws_instance" "web" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t3.micro"
  key_name      = aws_key_pair.deployer.key_name
}

resource "null_resource" "configure" {
  triggers = {
    instance_id  = aws_instance.web.id
    playbook_hash = filemd5("${path.module}/playbooks/web.yml")
  }

  provisioner "local-exec" {
    command = <<-EOT
      ansible-playbook -i '${aws_instance.web.public_ip},' \
        --private-key ${var.ssh_key_path} \
        --ssh-extra-args='-o StrictHostKeyChecking=no' \
        ${path.module}/playbooks/web.yml
    EOT
  }
}

import * as s3 from 'aws-cdk-lib/aws-s3';

// L1 — raw CloudFormation (like hand-writing aws_cloudformation_stack in Terraform)
const l1Bucket = new s3.CfnBucket(this, 'L1Bucket', {
  bucketEncryption: {
    serverSideEncryptionConfiguration: [{
      serverSideEncryptionByDefault: { sseAlgorithm: 'AES256' }
    }]
  }
});

// L2 — opinionated defaults (like a well-written Terraform module)
const l2Bucket = new s3.Bucket(this, 'L2Bucket', {
  encryption: s3.BucketEncryption.S3_MANAGED,
  blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
  versioned: true
});

package test

import (
	"testing"
	"github.com/gruntwork-io/terratest/modules/terraform"
	"github.com/stretchr/testify/assert"
)

func TestS3BucketIsPrivate(t *testing.T) {
	opts := &terraform.Options{
		TerraformDir: "../modules/s3",
		Vars: map[string]interface{}{"bucket_name": "test-byteai-bucket"},
	}
	defer terraform.Destroy(t, opts)
	terraform.InitAndApply(t, opts)
	acl := terraform.Output(t, opts, "bucket_acl")
	assert.Equal(t, "private", acl)
}

# terraform >= 1.5 — import block approach
locals {
  buckets = {
    assets = "my-assets-bucket-prod"
    logs   = "my-logs-bucket-prod"
  }
}

import {
  for_each = local.buckets
  to       = aws_s3_bucket.this[each.key]
  id       = each.value
}

resource "aws_s3_bucket" "this" {
  for_each = local.buckets
  bucket   = each.value
}

resource "aws_db_instance" "primary" {
  identifier        = "prod-postgres"
  instance_class    = "db.t3.medium"
  engine            = "postgres"
  allocated_storage = 100

  lifecycle {
    prevent_destroy = true
    ignore_changes  = [engine_version, snapshot_identifier]
  }
}

# CI gate: fail pipeline if destroy actions detected on critical resources
# terraform plan -out=tfplan && terraform show -json tfplan | \
#   jq '.resource_changes[] | select(.change.actions[] == "delete")' | grep -q . && exit 1

# .tflint.hcl
plugin "aws" {
  enabled = true
  version = "0.32.0"
  source  = "github.com/terraform-linters/tflint-ruleset-aws"
}

rule "terraform_required_version" {
  enabled = true
}

# CI pipeline step (bash)
terraform fmt -check -recursive . && \
  tflint --init && \
  tflint --recursive

# Terraform 1.5+ import block — killer feature when migrating FROM Bicep/CDK
# Generates config AND wires state without destroy/recreate

import {
  to = aws_s3_bucket.app_assets
  id = "my-app-assets-prod"
}

import {
  to = azurerm_resource_group.shared
  id = "/subscriptions/abc-123/resourceGroups/shared-rg"
}

# Multi-cloud in a single plan — structurally impossible in Bicep or CDK
resource "aws_s3_bucket" "app_assets" {
  bucket = "my-app-assets-prod"
}

resource "azurerm_resource_group" "shared" {
  name     = "shared-rg"
  location = "eastus"
}
